def count_requests(logs):
    counts = {}
    for entry in logs:
        counts[entry] = counts.get(entry, 0) + 1
    return counts

logs = [
    ('GET', '/users'),
    ('POST', '/users'),
    ('GET', '/users'),
    ('GET', '/health'),
    ('POST', '/users'),
]
result = count_requests(logs)
for key, total in result.items():
    print(f'{key}: {total}')
